/**
 * @generated by @flusk/cli
 * CLI command: flusk conversations-list
 */
import { Command } from 'commander';
import chalk from 'chalk';
import { createSqliteStorage } from '@flusk/resources';

export const conversationsListCommand = new Command('conversations-list')
  .description('List recent conversations')
  .option('-l, --limit <n>', 'Max conversations to show', '20')
  .option('-s, --status <status>', 'Filter: all|active|completed|abandoned', 'all')
  .action((opts) => {
    const storage = createSqliteStorage();
    const limit = parseInt(opts.limit, 10);
    const convos = storage.conversations.list(limit, 0);
    const filtered = opts.status === 'all'
      ? convos
      : convos.filter((c) => c.status === opts.status);

    if (filtered.length === 0) {
      console.log(chalk.dim('No conversations found.'));
      return;
    }

    const header = [
      pad('ID', 10), pad('Provider', 12), pad('Model', 20),
      pad('Turns', 6), pad('Cost', 10), pad('Status', 12), 'Last Call',
    ].join('  ');

    console.log(chalk.bold(header));
    console.log(chalk.dim('─'.repeat(90)));

    for (const c of filtered) {
      const row = [
        pad(c.id.slice(0, 8), 10),
        pad(c.provider, 12),
        pad(c.model, 20),
        pad(String(c.turnCount), 6),
        pad(`$${c.totalCost.toFixed(4)}`, 10),
        pad(c.status, 12),
        c.lastCallAt.slice(0, 16).replace('T', ' '),
      ].join('  ');
      console.log(row);
    }
  });

function pad(s: string, len: number): string {
  return s.length >= len ? s.slice(0, len) : s + ' '.repeat(len - s.length);
}
